import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.DmWB24NN.js";const g=JSON.parse('{"title":"CHAPTER 3: CLASSES","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 03_ Classes.md","filePath":"Book I - Core Rules/B01 - Chapter 03_ Classes.md"}'),i={name:"Book I - Core Rules/B01 - Chapter 03_ Classes.md"};function o(s,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="chapter-3-classes" tabindex="-1"><strong>CHAPTER 3: CLASSES</strong> <a class="header-anchor" href="#chapter-3-classes" aria-label="Permalink to &quot;**CHAPTER 3: CLASSES**&quot;">​</a></h1><p>A character&#39;s class defines their training before they became a mercenary, sellsword, or hired blade, taking contracts in the Known World. It is not destiny, and it is not identity, but the set of skills, disciplines, and learned capabilities they bring to a job that other people find too dangerous or too complicated to handle themselves.</p><p>Ten classes are available. They are organized into four groups, which share hit dice, attack bonus progression, and saving throw advancement. Within a group, individual classes differentiate through special abilities, requirements, and restrictions.</p><hr><h2 id="class-groups" tabindex="-1"><strong>Class Groups</strong> <a class="header-anchor" href="#class-groups" aria-label="Permalink to &quot;**Class Groups**&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Classes</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>Warrior</td><td>Fighter, Paladin, Ranger, Champion</td><td>d10</td><td>+1 per level</td></tr><tr><td>Wizard</td><td>Mage, Sorcerer</td><td>d4</td><td>+1 per 3 levels</td></tr><tr><td>Priest</td><td>Cleric, Druid</td><td>d8</td><td>+1 per 2 levels</td></tr><tr><td>Rogue</td><td>Thief, Bard</td><td>d6</td><td>+1 per 2 levels</td></tr></tbody></table><p>Hit dice are rolled at each level through the class&#39;s listed maximum. Beyond that level, the class grants a fixed hit point bonus per level instead. Warriors receive +3 HP per level beyond their maximum hit die, Priests and Rogues +2, Wizards +1.</p><hr><h2 id="ability-score-requirements" tabindex="-1"><strong>Ability Score Requirements</strong> <a class="header-anchor" href="#ability-score-requirements" aria-label="Permalink to &quot;**Ability Score Requirements**&quot;">​</a></h2><p>All classes carry minimum ability score requirements. Characters who do not meet a class&#39;s requirements may not select it. If no scores qualify a character for any class, the GM should allow a reroll or targeted score adjustment before play begins.</p><h3 id="table-3-1-class-ability-score-requirements" tabindex="-1"><strong>Table 3.1: Class Ability Score Requirements</strong> <a class="header-anchor" href="#table-3-1-class-ability-score-requirements" aria-label="Permalink to &quot;**Table 3.1: Class Ability Score Requirements**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class</th><th>STR</th><th>DEX</th><th>CON</th><th>INT</th><th>WIS</th><th>CHA</th></tr></thead><tbody><tr><td>Fighter</td><td>9</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Paladin</td><td>12</td><td>—</td><td>—</td><td>—</td><td>13</td><td>17</td></tr><tr><td>Ranger</td><td>13</td><td>13</td><td>14</td><td>—</td><td>14</td><td>—</td></tr><tr><td>Champion</td><td>12</td><td>—</td><td>—</td><td>—</td><td>13</td><td>17</td></tr><tr><td>Mage</td><td>—</td><td>—</td><td>—</td><td>9</td><td>—</td><td>—</td></tr><tr><td>Sorcerer</td><td>—</td><td>—</td><td>10</td><td>—</td><td>13</td><td>—</td></tr><tr><td>Cleric</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Druid</td><td>—</td><td>—</td><td>—</td><td>—</td><td>12</td><td>15</td></tr><tr><td>Thief</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Bard</td><td>—</td><td>12</td><td>—</td><td>13</td><td>—</td><td>13</td></tr></tbody></table><p>Characters who meet their class&#39;s prime requisite receive a +10% bonus to earned experience. Prime requisites are noted in each class entry.</p><hr><h2 id="ancestry-restrictions" tabindex="-1"><strong>Ancestry Restrictions</strong> <a class="header-anchor" href="#ancestry-restrictions" aria-label="Permalink to &quot;**Ancestry Restrictions**&quot;">​</a></h2><p>The following restrictions apply in addition to those established in Chapter 2.</p><table tabindex="0"><thead><tr><th>Class</th><th>Restrictions</th></tr></thead><tbody><tr><td>Champion</td><td>Unavailable to Val&#39;arian and Húldar</td></tr><tr><td>Sorcerer</td><td>Available to Human, Vartran, Húldar, and Aelár only</td></tr><tr><td>Druid</td><td>Available to Húldar and Aelár only. See The Druidic Compact, Chapter 2</td></tr><tr><td>Paladin</td><td>Available to Human, Badaki, and Ûrgon only</td></tr></tbody></table><p>All other classes follow Table 2.3 restrictions.</p><hr><h2 id="warrior-group" tabindex="-1"><strong>WARRIOR GROUP</strong> <a class="header-anchor" href="#warrior-group" aria-label="Permalink to &quot;**WARRIOR GROUP**&quot;">​</a></h2><p>Warriors advance fastest in combat. They gain attack bonuses every level, fight with the broadest range of weapons and armor, and accumulate the most hit points. What they lack relative to other groups — spells, thieving skills, social abilities — they compensate for through sustained martial superiority.</p><hr><h3 id="fighter" tabindex="-1"><strong>FIGHTER</strong> <a class="header-anchor" href="#fighter" aria-label="Permalink to &quot;**FIGHTER**&quot;">​</a></h3><p>Fighters are soldiers, mercenaries, and trained combatants. They represent the broadest martial tradition in the Known World: disciplined, adaptable, dangerous across virtually any weapon and any terrain. Other warrior classes specialize; Fighters refine.</p><p>In the Known World, the distinction between a Fighter and anyone else with a sword is depth of training. A farmer who picks up a weapon becomes a combatant. A Fighter has spent years learning how to use weight, leverage, timing, and terrain — and it shows after the first exchange.</p><p>Warriors who follow the Way of Boros may seek entry to Duskhold in Gwan&#39;tor — the highest available martial training in that tradition. See Book II, Chapter 5.</p><p><strong>Prime Requisite.</strong> Strength.</p><p><strong>Requirements.</strong> STR 9.</p><p><strong>Hit Dice.</strong> d10, through level 9. +3 HP/level thereafter.</p><p><strong>Weapons and Armor.</strong> All weapons and armor.</p><p><strong>Advancement.</strong> → Table 3.3: Fighter Advancement.</p><h4 id="special-abilities" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Weapon Specialization.</strong> Fighters may specialize in individual weapons. Specialization costs 2 Skill Points (SPs) and provides +1 to attack rolls, +2 to damage, and one additional attack per round at certain level thresholds. A Fighter may specialize in multiple weapons, but must meet the SP cost for each. Non-Fighters may not specialize.</p><p><strong>Multiple Attacks.</strong> Fighters gain additional attacks per round as they advance. The full progression is detailed in Chapter 7: Combat.</p><p><strong>Combat Maneuvers.</strong> Fighters have unrestricted access to all combat maneuvers and fighting styles described in Chapter 7.</p><p><strong>Skill Points.</strong> Fighters start with 7 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><hr><h3 id="table-3-3-fighter-advancement" tabindex="-1"><strong>Table 3.3: Fighter Advancement</strong> <a class="header-anchor" href="#table-3-3-fighter-advancement" aria-label="Permalink to &quot;**Table 3.3: Fighter Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d10</td><td>+1</td></tr><tr><td>2</td><td>2,000</td><td>2d10</td><td>+2</td></tr><tr><td>3</td><td>4,000</td><td>3d10</td><td>+3</td></tr><tr><td>4</td><td>8,000</td><td>4d10</td><td>+4</td></tr><tr><td>5</td><td>16,000</td><td>5d10</td><td>+5</td></tr><tr><td>6</td><td>32,000</td><td>6d10</td><td>+6</td></tr><tr><td>7</td><td>64,000</td><td>7d10</td><td>+7</td></tr><tr><td>8</td><td>125,000</td><td>8d10</td><td>+8</td></tr><tr><td>9</td><td>250,000</td><td>9d10</td><td>+9</td></tr><tr><td>10</td><td>500,000</td><td>9d10+3</td><td>+10</td></tr><tr><td>11+</td><td>+250,000/level</td><td>+3 HP/level</td><td>+1/level</td></tr></tbody></table><hr><h3 id="paladin" tabindex="-1"><strong>PALADIN</strong> <a class="header-anchor" href="#paladin" aria-label="Permalink to &quot;**PALADIN**&quot;">​</a></h3><p>A Paladin&#39;s authority comes from divine calling, not rank or appointment. They are answerable to their deity before any lord, contract, or comrade. This creates characters of genuine conviction and genuine inflexibility — properties that are useful in some situations and catastrophic in others.</p><p>In the Known World, Paladins exist in a complicated relationship with the Church of Tar&#39;amaan. The Church has its own warrior clergy and regards independent Paladins as either assets to be recruited or problems to be neutralized, depending on whose deity the Paladin serves. A Paladin of the Three Sisters operating inside Cadman-held Norderenn is doing something the Church considers heresy. That this heresy involves healing the sick and protecting the poor does not improve the Church&#39;s position on it.</p><p>Paladins must maintain a code of conduct consistent with their deity&#39;s demands. A Paladin who violates this code loses all special abilities until they atone — through deeds determined by their deity&#39;s clergy, or through direct divine mandate if the deity communicates directly. Lost levels are not recovered.</p><p>Duskhold in Gwan&#39;tor is the premier training ground for Boroite Paladins. Badakis enters by right; all others require a sponsor. See Book II, Chapter 5.</p><p><strong>Prime Requisite.</strong> Strength and Charisma.</p><p><strong>Requirements.</strong> STR 12, WIS 13, CHA 17. Lawful alignment.</p><p><strong>Available To:</strong> Human, Badaki, Ûrgon. All Badaki Paladins serve Boros. Ûrgon Paladins nearly always do the same — the exceptions have histories.</p><p><strong>Hit Dice.</strong> d10, through level 9. +3 HP/level thereafter.</p><p><strong>Weapons and Armor.</strong> All weapons and armor.</p><p><strong>Advancement.</strong> → Table 3.4: Paladin/Ranger Advancement.</p><h4 id="special-abilities-1" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-1" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Lay on Hands.</strong> Once per day, the Paladin may heal a number of hit points equal to twice their level. They may use this on themselves or on a willing recipient they touch.</p><p><strong>Detect Evil.</strong> At will, the Paladin may concentrate to sense evil intent or magical evil within 18 m. This requires one round of concentration and reveals presence, not identity or exact location.</p><p><strong>Divine Aura.</strong> The Paladin radiates an aura of protection: all allies within 3 m gain +1 to saving throws. This functions constantly and requires no activation.</p><p><strong>Saving Throw Bonus.</strong> Paladins receive an additional +2 bonus to all saving throws, stacking with the Divine Aura and any other modifiers.</p><p><strong>Turn Undead.</strong> As a cleric, at two levels below their actual Paladin level.</p><p><strong>Warhorse.</strong> At 4th level, the Paladin may call a warhorse of exceptional quality. The animal is loyal, responds to training beyond what normal horses accept, and shares some measure of the Paladin&#39;s divine protection. If the warhorse dies, a replacement cannot be called for one year.</p><p><strong>Divine Spellcasting.</strong> At 9th level, Paladins gain access to divine spells drawn from the Cleric list, beginning at 1st level. They cast as a Cleric four levels below their Paladin level.</p><p><strong>Restrictions.</strong> Paladins may not retain wealth beyond what covers basic expenses and equipment. Surplus must be donated to a religious institution or charitable cause within one month of acquisition. Paladins may employ no more than one henchman. They may associate with non-lawful party members but may not knowingly condone evil acts.</p><p><strong>Skill Points.</strong> Paladins start with 7 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><hr><h3 id="ranger" tabindex="-1"><strong>RANGER</strong> <a class="header-anchor" href="#ranger" aria-label="Permalink to &quot;**RANGER**&quot;">​</a></h3><p>Rangers are trackers, wilderness guides, and hunters who operate at the edges of settled land — or well beyond them. In the Known World, the edges are consequential: the Dead Lands require people who know how to move through them, and most people who attempt this without a Ranger&#39;s skillset do not return. The Emerald Corridor&#39;s caravans hire Rangers to navigate routes and deal with what lives along them.</p><p>The combat training of a Ranger integrates terrain as a factor rather than an obstacle. They fight differently outdoors than they do in a tavern, and they know it, and they try to ensure the fight happens outdoors.</p><p><strong>Prime Requisite.</strong> Strength and Wisdom.</p><p><strong>Requirements.</strong> STR 13, DEX 13, CON 14, WIS 14.</p><p><strong>Hit Dice.</strong> d10, through level 10. +3 HP/level thereafter. Rangers begin with only 1d8 at 1st level, gaining d10s from level 2 onward.</p><p><strong>Weapons and Armor.</strong> All weapons. All armor, but stealth and tracking abilities function only in light or no armor.</p><p><strong>Advancement.</strong> → Table 3.4: Paladin/Ranger Advancement.</p><h4 id="special-abilities-2" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-2" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Two-Weapon Fighting.</strong> Rangers may fight with a weapon in each hand with reduced penalties: −2 to the primary hand and −4 to the off hand, compared to −4/−8 for untrained fighters. High Dexterity may further reduce these penalties.</p><p><strong>Tracking.</strong> Rangers can follow trails through natural terrain. The player rolls 1d20 against the Ranger&#39;s Wisdom score; modifiers apply based on terrain, weather, passage of time, and the quarry&#39;s skill at concealment. On a success, the trail is followed; failure means the trail is lost and cannot be retried until conditions change.</p><p><strong>Favored Enemy.</strong> Rangers choose a favored enemy category at character creation — goblinoids, undead, humans, magical beasts, and so on. Against favored enemies, Rangers receive +4 to attack rolls and +4 to damage.</p><p><strong>Stealth.</strong> In natural terrain, while wearing non-metal armor, Rangers impose a −4 penalty on opponents&#39; surprise rolls. In dungeons or urban environments, this ability does not apply.</p><p><strong>Animal Empathy.</strong> Rangers can calm and communicate basic information to natural animals. This is not a magical ability; it reflects trained skill in reading and responding to animal behavior. It does not affect magical or undead animals.</p><p><strong>Skill Points.</strong> Rangers start with 7 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><h3 id="ranger-paths" tabindex="-1"><strong>Ranger Paths</strong> <a class="header-anchor" href="#ranger-paths" aria-label="Permalink to &quot;**Ranger Paths**&quot;">​</a></h3><p>At 8th level, a Ranger chooses one of two paths. The choice is permanent and reflects the direction their career has taken over the preceding years.</p><p><strong>Path of the Warden</strong></p><p>Wardens are Rangers who have cultivated a genuine relationship with the natural world — and, more specifically, with the Hyerophancy&#39;s awareness of them. This is not guaranteed. A Ranger does not automatically earn Druidic approval simply by spending time outdoors. The relationship develops through play: acts of genuine stewardship, assistance rendered to Druidic interests, time spent in Alvengaard or with Húldar communities, and eventually a formal recognition from a Druid of at least 7th level.</p><p>When a Warden earns that recognition, they gain access to nature spells drawn from the Druid spell list, beginning at 1st level. Their spell progression begins at the level they receive recognition — which may be 8th or later — and advances from that point. Casting requires no investiture from the Hyerophancy; this is not Druidic magic in the institutional sense. What the Warden accesses is the natural attunement their years of wilderness work have produced, filtered through whatever teaching the approving Druid provides.</p><p>If no Druidic recognition is earned, a Ranger who intends to walk this path simply does not gain spellcasting. The path remains open as long as the Ranger pursues it. This is a design feature, not a gap — the approval mechanic exists to generate play, not to gatekeep a mechanical reward indefinitely.</p><p><em>GMs should treat the Druidic approval as a meaningful milestone that emerges from actual campaign events, not a formality to be resolved off-screen. The Ranger&#39;s effort to earn it, and the Druid&#39;s eventual decision about whether they have, can generate sessions on their own.</em></p><p><strong>Path of the Scout</strong></p><p>Scouts are pure operatives — marksmen, trackers, and infiltrators who have concluded that the wilderness is not a spiritual environment but a professional one. At 8th level, instead of pursuing spellcasting, Scouts receive the following permanent bonuses:</p><p><em>Master Archer.</em> Scouts gain +2 to attack rolls and +3 to damage rolls with bows and crossbows. This stacks with all existing Dexterity modifiers and weapon proficiency bonuses.</p><p><em>Ghost Movement.</em> The Scout&#39;s Stealth ability, previously limited to non-metal armor in natural terrain, now applies in any environment — including dungeons, urban settings, and underground passages — while wearing leather armor or lighter. The surprise penalty imposed on opponents increases to −6 in natural terrain.</p><p><em>Improved Tracking.</em> When making a Tracking roll, the Scout rolls twice and uses the better result. In terrain the Scout has designated as a favored operating environment (chosen at this level), failed tracking rolls can be retried after one turn rather than waiting for conditions to change.</p><hr><h3 id="table-3-4-paladin-ranger-advancement" tabindex="-1"><strong>Table 3.4: Paladin/Ranger Advancement</strong> <a class="header-anchor" href="#table-3-4-paladin-ranger-advancement" aria-label="Permalink to &quot;**Table 3.4: Paladin/Ranger Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP (Paladin)</th><th>XP (Ranger)</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>0</td><td>1d10 *</td><td>+1</td></tr><tr><td>2</td><td>2,250</td><td>2,250</td><td>2d10</td><td>+2</td></tr><tr><td>3</td><td>4,500</td><td>4,500</td><td>3d10</td><td>+3</td></tr><tr><td>4</td><td>9,000</td><td>9,000</td><td>4d10</td><td>+4</td></tr><tr><td>5</td><td>18,000</td><td>18,000</td><td>5d10</td><td>+5</td></tr><tr><td>6</td><td>36,000</td><td>36,000</td><td>6d10</td><td>+6</td></tr><tr><td>7</td><td>75,000</td><td>75,000</td><td>7d10</td><td>+7</td></tr><tr><td>8</td><td>150,000</td><td>150,000</td><td>8d10</td><td>+8</td></tr><tr><td>9</td><td>300,000</td><td>300,000</td><td>9d10</td><td>+9</td></tr><tr><td>10</td><td>600,000</td><td>600,000</td><td>9d10+3</td><td>+10</td></tr><tr><td>11+</td><td>+300,000/level</td><td>+300,000/level</td><td>+3 HP/level</td><td>+1/level</td></tr></tbody></table><p>* Rangers roll 1d8 at 1st level only.</p><hr><h3 id="champion" tabindex="-1"><strong>CHAMPION</strong> <a class="header-anchor" href="#champion" aria-label="Permalink to &quot;**CHAMPION**&quot;">​</a></h3><p>Champions are honor-bound warriors — not divine instruments, not mere soldiers. They follow a Code, and the Code defines them more precisely than any weapon or armor. The Code may derive from a religious tradition, a knightly institution, a nation&#39;s martial philosophy, or a personal oath sworn under specific circumstances. What it cannot be is vague. A Code with no specific tenets has no weight, and a Champion without a Code is an ordinary Fighter with better charisma.</p><p>In the Known World, Champions appear most visibly among the orders of the Emerald Corridor nations — Bellaria&#39;s sword-lodges, the disciplined dueling houses of Solara, the warrior cadres that Norderenn&#39;s resistance movements have formalized into something with ranks and oaths. A Badaki Champion is rare and striking. An Ûrgon who has taken vows of protection and repudiated the purpose the Darkness forged them for is something most people will only hear about secondhand.</p><p>Champions are not Paladins. They perform no miracles. They call on no deity. What they have instead is absolute clarity about what they will and will not do, and the skill to back that clarity with force.</p><p><strong>The Code.</strong> At character creation, the player and GM establish the Champion&#39;s Code together — a set of specific, enforceable tenets that govern conduct. Three to five tenets are standard. Tenets should be concrete enough to create genuine decisions at the table: <em>I do not strike an opponent who has surrendered</em> is a tenet. <em>I am honorable</em> is not.</p><p>A Champion who violates their Code ceases gaining experience in the Champion class until they atone. The form of atonement is narrative — a quest, a sacrifice, a public act of amends — and its scope should match the severity of the violation. Minor infractions may require a single session&#39;s worth of effort. Fundamental betrayals of the Code may require significantly more. The class&#39;s abilities remain functional during this period; only advancement halts.</p><p>Duskhold trains Champions in the Way of Boros. For non-Badakis, entry requires a Badaki sponsor and demonstrated adherence to Boros&#39;s ethos. See Book II, Chapter 5.</p><p><strong>Prime Requisite.</strong> Strength and Charisma.</p><p><strong>Requirements.</strong> STR 12, WIS 13, CHA 17.</p><p><strong>Available To:</strong> All. Húldar Champions exist, but rarely. Alvengaard&#39;s druidic traditions share little with the Champion&#39;s public oath-structure, and full plate in the deep forest announces itself before the wearer does.</p><p><strong>Hit Dice.</strong> d10, through level 9. +3 HP/level thereafter.</p><p><strong>Weapons and Armor.</strong> All weapons and armor.</p><p><strong>Advancement.</strong> → Table 3.5: Champion Advancement.</p><h4 id="special-abilities-3" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-3" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Disciplined Defense.</strong> Champions receive +1 to Armor Class at all times. This bonus applies whether armored or unarmored, conscious or incapacitated, and stacks with all other AC sources.</p><p><strong>Weapon Mastery.</strong> At character creation, the Champion chooses one weapon and gains specialization in it for free, without spending CSPs. This reflects years of dedicated training before the character began adventuring.</p><p><strong>Inspiring Presence.</strong> When the Champion is conscious and visible to allies in combat, those allies gain +1 to morale checks and saves against fear effects. This is passive and requires no action.</p><p><strong>Steadfast.</strong> At 7th level, Champions become immune to magical fear and to non-magical fear from mundane sources. They may still feel fear — they simply cannot be compelled to flee by it.</p><p><strong>Champion&#39;s Reputation.</strong> At 9th level, the Champion&#39;s adherence to their Code has accumulated enough witnessed history that their name carries weight. Their reaction modifier with NPCs who have heard of them improves by +2, for better or worse, depending on how their Code is regarded in that region.</p><p><strong>Skill Points.</strong> Champions start with 7 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><hr><h3 id="table-3-5-champion-advancement" tabindex="-1"><strong>Table 3.5: Champion Advancement</strong> <a class="header-anchor" href="#table-3-5-champion-advancement" aria-label="Permalink to &quot;**Table 3.5: Champion Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d10</td><td>+1</td></tr><tr><td>2</td><td>2,250</td><td>2d10</td><td>+2</td></tr><tr><td>3</td><td>4,500</td><td>3d10</td><td>+3</td></tr><tr><td>4</td><td>9,000</td><td>4d10</td><td>+4</td></tr><tr><td>5</td><td>18,000</td><td>5d10</td><td>+5</td></tr><tr><td>6</td><td>36,000</td><td>6d10</td><td>+6</td></tr><tr><td>7</td><td>75,000</td><td>7d10</td><td>+7</td></tr><tr><td>8</td><td>150,000</td><td>8d10</td><td>+8</td></tr><tr><td>9</td><td>300,000</td><td>9d10</td><td>+9</td></tr><tr><td>10</td><td>600,000</td><td>9d10+3</td><td>+10</td></tr><tr><td>11+</td><td>+300,000/level</td><td>+3 HP/level</td><td>+1/level</td></tr></tbody></table><hr><h2 id="wizard-group" tabindex="-1"><strong>WIZARD GROUP</strong> <a class="header-anchor" href="#wizard-group" aria-label="Permalink to &quot;**WIZARD GROUP**&quot;">​</a></h2><p>Wizards advance slowly in combat. Their hit dice are small, their weapon and armor options are narrow, and their attack bonuses accumulate at one-third the rate of Warriors. These are not oversights — they are the cost of magic. A wizard at full capacity outranges and outscales most other classes in raw effect. A wizard who has spent their prepared spells for the day is a problem their party has to protect.</p><hr><h3 id="mage" tabindex="-1"><strong>MAGE</strong> <a class="header-anchor" href="#mage" aria-label="Permalink to &quot;**MAGE**&quot;">​</a></h3><p>Mages are scholars of arcane magic. They study the theoretical frameworks underlying spellcasting, fill grimoires with learned formulae, and advance through the painstaking process of formal magical education. What distinguishes Mages from the generically magical is that they understand what they are doing — they can examine a new effect, model it against known principles, and build from it. The actual casting of a spell is almost secondary to that architecture of understanding.</p><p>In the Known World, Mages are most concentrated around the Order of Magnus and the Chroniclers — the former because the Order has a direct interest in controlled magical research, the latter because magical knowledge is a category of knowledge that Chroniclers find professionally irresistible. Independent Mages exist in every major city. The Church of Tar&#39;amaan makes this independence uncomfortable in Cadman-controlled territory.</p><p><strong>Prime Requisite.</strong> Intelligence.</p><p><strong>Requirements.</strong> INT 9.</p><p><strong>Hit Dice.</strong> d4, through level 10. +1 HP/level thereafter.</p><p><strong>Weapons.</strong> Dagger, staff, dart, sling. No armor.</p><p><strong>Advancement.</strong> → Table 3.6: Mage/Sorcerer Advancement.</p><h4 id="special-abilities-4" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-4" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Skill Points.</strong> Mages start with 6 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 6 and 7.</p><p><strong>Spellbook.</strong> Mages record their spells in a grimoire. A Mage begins play with a number of 1st-level spells equal to their Intelligence modifier plus three, drawn from the Wizard spell list. Additional spells are acquired through study, copying from scrolls, or successfully learning from another Mage&#39;s grimoire. Learning a spell requires a percentile roll against the Learn Spell chance from Table 1.4. Failure means the spell cannot be attempted again until the Mage gains a level.</p><p><strong>Spell Memorization.</strong> Mages memorize spells from their grimoire before rest periods and cast them from memory. A memorized spell is expended when cast. The number of spells memorized per level is detailed in the Wizard Spell Progression table in Appendix A.</p><p><strong>Scroll Use.</strong> Mages can scribe spells they know onto scrolls, and can cast from scrolls of spells they have not yet learned. Scribing requires one day per spell level and consumes 100 gp per spell level in materials.</p><p><strong>High Solaran.</strong> Mages learn High Solaran as part of their arcane education: the standard written language of the Order of Magnus and all formal arcane scholarship. Spellbooks are recorded in it. See Book II, Chapter 5. It does count on the total number of languages the character knows at character creation.</p><p><strong>Schools of Magic.</strong> Mages choose at character creation whether to practice as a generalist or a specialist.</p><ul><li><em>Generalists</em> have access to all schools of magic with no restrictions. They do not receive school-specific bonuses.</li><li><em>Specialists</em> choose one school of magic and dedicate their study to it. They receive one additional spell slot per spell level in their chosen school, a +15% bonus to their Learn Spell roll for spells of that school, and automatically know one additional spell of their school at each level they gain access to a new spell level. The trade-off: Specialists cannot learn spells from their opposing school and must spend two spell slots to memorize any spell from their secondary-opposed school. Opposing schools are listed in the table below.</li></ul><h4 id="spell-components" tabindex="-1"><strong>Spell Components</strong> <a class="header-anchor" href="#spell-components" aria-label="Permalink to &quot;**Spell Components**&quot;">​</a></h4><p>Specialists develop such mastery of their school&#39;s underlying principles that material components become redundant for spells within it. A Specialist may cast any spell from their chosen school without material components and without penalty on the potency axis. This exemption applies only to their chosen school. Spells from other accessible schools require material components as normal.</p><p>A Specialist who chooses Illusion/Phantasm is colloquially called an Illusionist. The term refers to the specialization, not a separate class.</p><p><strong>Schools of Magic and Opposition:</strong></p><table tabindex="0"><thead><tr><th>School</th><th>Opposed Schools</th><th>Title</th></tr></thead><tbody><tr><td>Abjuration</td><td>Alteration</td><td>Abjurer</td></tr><tr><td>Alteration</td><td>Abjuration, Necromancy</td><td>Transmuter</td></tr><tr><td>Conjuration/Summoning</td><td>Greater Divination</td><td>Conjurer</td></tr><tr><td>Divination</td><td>Illusion/Phantasm</td><td>Diviner</td></tr><tr><td>Greater Divination</td><td>Conjuration/Summoning</td><td>Oracle</td></tr><tr><td>Enchantment/Charm</td><td>Invocation/Evocation</td><td>Enchanter</td></tr><tr><td>Illusion/Phantasm</td><td>Divination, Necromancy</td><td>Illusionist</td></tr><tr><td>Invocation/Evocation</td><td>Enchantment/Charm</td><td>Invoker</td></tr><tr><td>Necromancy</td><td>Alteration, Illusion/Phantasm</td><td>Necromancer</td></tr></tbody></table><h4 id="the-gauntlet" tabindex="-1"><strong>The Gauntlet</strong> <a class="header-anchor" href="#the-gauntlet" aria-label="Permalink to &quot;**The Gauntlet**&quot;">​</a></h4><p>When the mage first joins the Order, at 1st level, they hold the status of the Apprentice - although he’s already free from their master’s will, they are considered in a probationary stage until reaching 2nd level, when they will attend the <em>Trials of Magnus</em> to receive their Gauntlet - if they succeed.</p><p>The Gauntlet is the sigil earned by mages who complete the Trials of Magnus, inscribed on the mage&#39;s dominant hand: perceptible to touch but invisible to non-magical sight. It cannot be transferred, removed, or replicated. After receiving the Gauntlet, the mage is now an Adept of the Order and has complete control and responsibility over their actions and studies. GMs and players must discuss these trials, and it’s something that will happen in-game.</p><h4 id="failing-the-trials" tabindex="-1"><strong>Failing the Trials</strong> <a class="header-anchor" href="#failing-the-trials" aria-label="Permalink to &quot;**Failing the Trials**&quot;">​</a></h4><p>If a mage fails their trial, they will be kept in Apprentice status and can attempt the trial again in the next season. The mage can still learn spells, acquire new levels, and go on adventures, but their access to the inner sections of Dolmas will only be allowed with express permission from the Mage’s master. A mage who fails the trials more than three times will be considered unfitted to become a full mage and be kept in Apprentice status forever. The player will need to multiclass their character, starting a new class for the character.</p><h4 id="the-mage-s-name" tabindex="-1"><strong>The Mage’s Name</strong> <a class="header-anchor" href="#the-mage-s-name" aria-label="Permalink to &quot;**The Mage’s Name**&quot;">​</a></h4><p>Upon completing the Gauntlet, a Mage may choose a new name. The Order does not require it. What it recognizes is that the Adept who survived the Gauntlet is not the person who entered — the trial strips pretense from a mage&#39;s relationship to magic in ways that are hard to explain to anyone who hasn&#39;t been through it. A new name, chosen by the Adept alone, is one way to mark what changed. Some keep the name they were born with. Some spend years deciding. The Order files both and recognizes whichever the Adept prefers. What the Order does not recognize is the name being chosen by anyone other than the Adept.</p><hr><h3 id="sorcerer" tabindex="-1"><strong>SORCERER</strong> <a class="header-anchor" href="#sorcerer" aria-label="Permalink to &quot;**SORCERER**&quot;">​</a></h3><p>Sorcerers do not study magic. They receive it — from a patron, a teacher, an entity with power and a reason to share some fraction of it. The distinction is philosophically significant in the Known World and practically significant at the table. A Mage who loses their grimoire can reconstruct it. A Sorcerer who loses their patron has lost the only channel through which they learn anything new.</p><p>The First Gift of Magic, in the theology of the Three Sisters, went to the Eymanarynn — the original dragonkin from whom the Vartran descend — and to the Húldar, through Ilya&#39;s direct intervention before the Second Era. Sorcery, for these ancestries, is reaching back toward something that was always theirs. Aelár carries that inheritance more tenuously — the same blood, the same ancient claim, attenuated by centuries of dispersal — and the Hyerophancy is less willing to acknowledge it from them than from Húldar. For Humans, it is reaching toward something they were never meant to have, acquired through the specific contract of a patron relationship.</p><p>A Sorcerer who cannot name their patron is not a Sorcerer. This is a practical rule as much as a philosophical one: the Known World has things in it that offer magical teaching for reasons of their own, and a Sorcerer who does not know what their patron is and what it wants has made a commitment they do not fully understand. The GM should work with the player at character creation to establish the patron&#39;s nature — it need not be known to other characters, but it should be known to the player.</p><p><strong>Social position by ancestry.</strong></p><p>Vartran Sorcerers are respected within Bal&#39;mekh as the most direct inheritors of Eymanarynn&#39;s gift. The blood is there; the practice follows naturally.</p><p>Húldar Sorcerers face less stigma than Húldar Mages. A Mage learns from writings — from the accumulated notation of scholars who systematized something the Húldar received directly. A Sorcerer at least draws from a channel that has ancestral legitimacy. The remaining stigma is pointed: pledging yourself to a patron signals dependence, and Vengardian culture has no admiration for it. A Húldar Sorcerer can work within Alvengaard&#39;s political structures if they keep their patron relationship quiet. They simply cannot advance within them.</p><p>Aelár Sorcerers carry the same ancestral argument Húldar do — the First Gift touched their forebears too, however distantly — and the Hyerophancy is even less willing to hear it from them. An Aelár who practices Sorcery inside Alvengaard&#39;s territory does so with the full weight of Hyerophantic disapproval applied to Aelár generally, compounded by the additional insult of claiming a magical lineage the High Council considers Alvengaard&#39;s alone to steward. Outside Alvengaard, Aelár Sorcerers attract no more attention than anyone else practicing arcane magic in a world that already distrusts it.</p><p>Human Sorcerers carry no ancestral legitimacy and no ancestral stigma. They found an arrangement that works and are using it.</p><p><strong>Prime Requisite.</strong> Wisdom.</p><p><strong>Requirements.</strong> WIS 13, CON 10.</p><p><strong>Available To.</strong> Human, Vartran, Húldar, Aelár only.</p><p><strong>Hit Dice.</strong> d4, through level 10. +1 HP/level thereafter.</p><p><strong>Weapons.</strong> Dagger, staff, dart, sling. No armor.</p><p><strong>Cannot Multiclass With.</strong> Mage, Cleric.</p><p><strong>Advancement.</strong> → Table 3.6: Mage/Sorcerer Advancement.</p><h4 id="special-abilities-5" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-5" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Skill Points.</strong> Sorcerers start with 6 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 6 and 7.</p><p><strong>Arcane Attunement.</strong> Sorcerers do not use spellbooks. They know their spells — taught and internalized through meditation. The number of spells a Sorcerer knows per spell level is determined by Wisdom rather than Intelligence (consult the Max Spells Per Level column in Table 1.5 in place of the Intelligence equivalent). Adding a new spell requires instruction from their patron or another Sorcerer who knows the spell, followed by a number of days of meditation equal to the spell&#39;s level. No Learn Spell roll is required; if the instruction and meditation are completed, the spell is learned.</p><p><strong>Spell Memorization.</strong> As Mage. Sorcerers memorize from their internalized knowledge rather than a written grimoire.</p><p><strong>Cannot Use Scrolls.</strong> Sorcerers cannot read magic. The written formula of a scroll represents a tradition of arcane scholarship — structured notation, theoretical underpinning, precise symbolic language — that a Sorcerer has never acquired. They can identify that a scroll is magical, and they understand what it does if they already know the spell. They cannot cast from it. This is not a limitation that can be trained away; it is a fundamental difference in how Sorcerers receive and hold magical knowledge.</p><p><strong>Schools of Magic.</strong> Sorcerers practice as generalists. The specialization path is not available to them — Sorcerous knowledge is received, not architecturally constructed, and the patron determines what is and is not taught.</p><p><strong>Arcane Surge.</strong> A Sorcerer may push beyond their memorized slots by drawing directly on their life force. When casting a spell from a memorized slot, the Sorcerer may choose one of two effects before rolling:</p><ul><li><em>Potency Boost:</em> The spell is cast at enhanced effect — damage increases by one die step, or effect strength improves by one category, or the target&#39;s saving throw is made at −2. Cost: HP equal to the spell&#39;s level × 3.</li><li><em>Double-Cast:</em> The memorized slot is not expended on this casting. The Sorcerer may cast the same spell once more before their next rest, at which point the slot is expended normally. Cost: HP equal to the spell&#39;s level × 5.</li></ul><p>The Sorcerer chooses which benefit to take at the moment of casting, before any dice are rolled. HP spent this way cannot reduce the Sorcerer below 0 — a Sorcerer at 3 HP cannot Double-Cast a 2nd-level spell. A Sorcerer reduced to exactly 0 HP by this cost falls unconscious immediately after the spell resolves.</p><p>The total number of surges per day — both Potency Boosts and Double-Casts combined — is determined by the Sorcerer&#39;s Wisdom score, using the same cap table as Mages (who use Intelligence in its place). The once-per-rest-per-spell restriction also applies: the same spell cannot be Double-Cast twice in a single day. See Chapter 13 for the full cap table. Sorcerers do not use material components for this purpose. The cost is themselves.</p><h4 id="patrons" tabindex="-1"><strong>Patrons</strong> <a class="header-anchor" href="#patrons" aria-label="Permalink to &quot;**Patrons**&quot;">​</a></h4><p><strong>Patron Bond.</strong> Once per session, a Sorcerer may meditate briefly to ask their patron a question. The patron is not omniscient, not always willing to answer, and not reliably honest. The GM plays the patron. This is not a mechanical ability with defined outcomes, but an established fictional relationship with ongoing consequences: the patron is a recurring NPC with their own agenda, their demands will arrive at inconvenient moments, and the obligations they create fall on the Sorcerer in ways the rest of the party did not sign up for and will have opinions about.</p><p><strong>Patron Demand.</strong> Once every three sessions, the GM secretly rolls a d6. On a 1, the patron reaches out with a demand.</p><p>The nature of the demand reflects the patron&#39;s character and interests: an errand, a piece of information, a person located or eliminated, an object retrieved or destroyed, or something stranger, depending on what the patron is. The demand arrives through whatever channel fits the established fiction — a voice in a dream, a message that appears where no one put it, an intermediary who knows too much, a sudden and specific compulsion.</p><p>The Sorcerer may refuse.</p><p>If they do, the patron withdraws their teaching. The Sorcerer retains spells already known but cannot learn new spells until they fulfill the outstanding demand or formally sever the patronage relationship. Severing is possible but permanent — a Sorcerer without a patron cannot learn new spells. Establishing a new patron requires the same kind of campaign-level effort that produced the original, and a second patron will know the first relationship ended badly.</p><p>Repeated refusals escalate. Two refusals might mean the patron communicates displeasure directly; three might mean active interference in the Sorcerer&#39;s activities; a fourth might mean the patron calls in obligations of their own. A patron who considers the relationship definitively broken may strip the Sorcerer of previously learned spells.</p><p><em>The once-every-three-sessions default assumes a campaign where the patron relationship is a recurring pressure rather than the campaign&#39;s central focus. GMs running a campaign where the patron is central can increase frequency. The d6 roll is a prompt, not a mandate — if a 1 comes up at a moment that would derail rather than enrich the session, hold the demand for a better entry point.</em></p><hr><h3 id="table-3-6-mage-sorcerer-advancement" tabindex="-1"><strong>Table 3.6: Mage/Sorcerer Advancement</strong> <a class="header-anchor" href="#table-3-6-mage-sorcerer-advancement" aria-label="Permalink to &quot;**Table 3.6: Mage/Sorcerer Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d4</td><td>+0</td></tr><tr><td>2</td><td>2,500</td><td>2d4</td><td>+0</td></tr><tr><td>3</td><td>5,000</td><td>3d4</td><td>+1</td></tr><tr><td>4</td><td>10,000</td><td>4d4</td><td>+1</td></tr><tr><td>5</td><td>20,000</td><td>5d4</td><td>+1</td></tr><tr><td>6</td><td>40,000</td><td>6d4</td><td>+2</td></tr><tr><td>7</td><td>60,000</td><td>7d4</td><td>+2</td></tr><tr><td>8</td><td>90,000</td><td>8d4</td><td>+2</td></tr><tr><td>9</td><td>135,000</td><td>9d4</td><td>+3</td></tr><tr><td>10</td><td>250,000</td><td>10d4</td><td>+3</td></tr><tr><td>11+</td><td>+375,000/level</td><td>+1 HP/level</td><td>+1 per 3 levels</td></tr></tbody></table><hr><h2 id="priest-group" tabindex="-1"><strong>PRIEST GROUP</strong> <a class="header-anchor" href="#priest-group" aria-label="Permalink to &quot;**PRIEST GROUP**&quot;">​</a></h2><p>Priests draw power from outside themselves — from the natural world, from divine entities, or from the accumulated spiritual force of their faith. They advance more slowly than Warriors in combat but considerably faster than Wizards, and their spellcasting draws from a pool that refreshes daily rather than a finite memorized list. Their restrictions are correspondingly significant: they answer to powers that have requirements.</p><hr><h3 id="cleric" tabindex="-1"><strong>CLERIC</strong> <a class="header-anchor" href="#cleric" aria-label="Permalink to &quot;**CLERIC**&quot;">​</a></h3><p>Clerics are the institutional face of divine power. They serve a deity through formal religious organization — not private conviction, not personal relationship, but hierarchical membership in a church or temple structure that has its own politics, its own demands, and its own interpretation of what their deity wants.</p><p>In the Known World, a Cleric operating independently of their church is unusual and usually means something went wrong. Clerics of the Three Sisters in Norderenn are currently doing their work in basements and backrooms because the Cadman occupation considers their church a political liability. Clerics of the Church of Tar&#39;amaan are among the most powerful institutional actors in the Cadman Empire. A Cleric&#39;s relationship with their institution is part of their character — it creates obligations, provides resources, and generates enemies based on whose prayers their god is receiving.</p><p><strong>Prime Requisite.</strong> Wisdom.</p><p><strong>Requirements.</strong> None beyond ancestry restrictions.</p><p><strong>Hit Dice.</strong> d8, through level 9. +2 HP/level thereafter.</p><p><strong>Weapons.</strong> Clerics are restricted to blunt weapons by the traditions of most religious orders. Specific faiths may permit edged weapons; this is established by tradition, not by the rules. The common default: club, flail, hammer, mace, staff. No bows or crossbows.</p><p><strong>Armor.</strong> Any, including shields.</p><p><strong>Advancement.</strong> → Table 3.7: Cleric Advancement.</p><h4 id="special-abilities-6" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-6" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Divine Spellcasting.</strong> Clerics memorize and cast spells drawn from the Priest spell list. Spell slots are detailed in the Cleric Spell Progression table in Appendix A. Unlike Mages, Clerics do not maintain spellbooks — their prayers are addressed directly to their deity. Clerics also receive bonus spells based on Wisdom score, as detailed in Table 1.5.</p><p><strong>Turn Undead.</strong> Clerics can turn or destroy undead creatures by presenting their holy symbol. The Turn Undead table determines the result based on the Cleric&#39;s level and the undead creature&#39;s HD. Results range from the undead fleeing to instantaneous destruction. See Chapter 12: The Undead.</p><p><strong>Deity Requirements.</strong> A Cleric who acts against their deity&#39;s core principles loses all spellcasting ability until they atone in a manner prescribed by their faith. Unlike the Champion&#39;s Code, this atonement requires the intervention of a higher-ranking member of the clergy or, at the GM&#39;s discretion, a direct divine communication.</p><p><strong>Skill Points.</strong> Clerics start with 5 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 6 and 7.</p><h4 id="the-cleric-s-name" tabindex="-1"><strong>The Cleric’s Name</strong> <a class="header-anchor" href="#the-cleric-s-name" aria-label="Permalink to &quot;**The Cleric’s Name**&quot;">​</a></h4><p>Clerics who serve institutional orders may receive an ordination name upon entering formal service — a name drawn from their faith&#39;s theological tradition, distinct from the one they were born with. The birth name does not disappear; it becomes private, used by family and in personal prayer. What that boundary means varies by institution and by the individual. The Church of Tar&#39;amaan practices this formally, with a specific naming lexicon and multiple ranks of name-change at higher ordinations. Other faiths handle it differently or not at all. A cleric who gives their birth name to a stranger outside the family is making a choice, and it registers as one.</p><hr><h3 id="table-3-7-cleric-advancement" tabindex="-1"><strong>Table 3.7: Cleric Advancement</strong> <a class="header-anchor" href="#table-3-7-cleric-advancement" aria-label="Permalink to &quot;**Table 3.7: Cleric Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d8</td><td>+0</td></tr><tr><td>2</td><td>1,500</td><td>2d8</td><td>+0</td></tr><tr><td>3</td><td>3,000</td><td>3d8</td><td>+1</td></tr><tr><td>4</td><td>6,000</td><td>4d8</td><td>+1</td></tr><tr><td>5</td><td>13,000</td><td>5d8</td><td>+1</td></tr><tr><td>6</td><td>27,500</td><td>6d8</td><td>+2</td></tr><tr><td>7</td><td>55,000</td><td>7d8</td><td>+2</td></tr><tr><td>8</td><td>110,000</td><td>8d8</td><td>+2</td></tr><tr><td>9</td><td>225,000</td><td>9d8</td><td>+3</td></tr><tr><td>10</td><td>450,000</td><td>9d8+2</td><td>+3</td></tr><tr><td>11+</td><td>+225,000/level</td><td>+2 HP/level</td><td>+1 per 2 levels</td></tr></tbody></table><h4 id="cleric-weapon-allowances-by-faith" tabindex="-1"><strong>Cleric Weapon Allowances by Faith</strong> <a class="header-anchor" href="#cleric-weapon-allowances-by-faith" aria-label="Permalink to &quot;**Cleric Weapon Allowances by Faith**&quot;">​</a></h4><p>The default permitted weapons for Clerics are: club, footman&#39;s flail, horseman&#39;s flail, footman&#39;s mace, horseman&#39;s mace, morning star, quarterstaff, war hammer. No bows, crossbows, or edged weapons unless a faith entry specifies otherwise. Faiths not listed here — including minor traditions and folk practices — use the default list.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Faith</th><th style="text-align:left;">Permitted Weapons</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;">Ilianism</td><td style="text-align:left;">Default list + sling</td><td style="text-align:left;">No edged weapons.</td></tr><tr><td style="text-align:left;">Church of Tar&#39;amaan</td><td style="text-align:left;">Longsword, bastard sword, khopesh, spear, javelin, all polearms</td><td style="text-align:left;">No blunt weapons of any kind. No bows or crossbows. NPC Clerics only — see B02, Ch. 6.</td></tr><tr><td style="text-align:left;">Way of Boros</td><td style="text-align:left;">Default list + hand axe, battle axe, bastard sword (either grip), two-handed sword, all polearms</td><td style="text-align:left;">No bows or crossbows.</td></tr><tr><td style="text-align:left;">Druidic Tradition</td><td style="text-align:left;">-</td><td style="text-align:left;">Druids follow their class weapon list regardless of tradition. See Druid class entry.</td></tr></tbody></table><p><em>The Faith of the Nine does not produce Clerics. Val&#39;arian divine casters are Sorcerers; the Nine serve as patrons. See B02, Ch. 6.</em></p><hr><h3 id="druid" tabindex="-1"><strong>DRUID</strong> <a class="header-anchor" href="#druid" aria-label="Permalink to &quot;**DRUID**&quot;">​</a></h3><p>Druids are the Hierophancy&#39;s sanctioned practitioners of natural magic. They are not nature lovers in a general sense — the Known World has plenty of those — but formally invested agents of a specific institution with a specific theological position about who has the right to channel the forces moving through the natural world, and who does not. The cycle they attune to — growth, death, renewal — is not merely doctrine. It reflects something older and larger than any institution, and senior druids feel its fluctuations before any instrument records them. The specific betrayal of that attunement, the rejection of the cycle&#39;s most fundamental law, is treated by the Hyerophancy as categorically distinct from any other transgression a Druid can commit. What that betrayal produces, the Hyerophancy does not discuss outside its inner council.</p><p>The Druidic Compact, detailed in Chapter 2, governs who can become a Druid and what happens to those who attempt it outside the Compact&#39;s terms. This chapter covers only the mechanical substance of the class.</p><p>Druids in the Known World function as protectors of natural spaces, mediators between communities and the land they depend on, and occasionally as intelligence assets for the Hierophancy, which has interests in everything that affects the forest and the forces running through it. An adventuring Druid is usually serving one of these functions in a context that requires moving beyond Alvengaard&#39;s borders.</p><p><strong>Prime Requisite.</strong> Wisdom.</p><p><strong>Requirements.</strong> WIS 12, CHA 15.</p><p><strong>Available To.</strong> Húldar and Aelár only.</p><p><strong>Hit Dice.</strong> d8, through level 9. +2 HP/level thereafter.</p><p><strong>Weapons.</strong> Club, sickle, dart, spear, dagger, scimitar, staff, sling. No metal armor — Druids wear leather, hide, or wooden armor only, and carry wooden shields. Metal armor severs the attunement that their spellcasting depends on.</p><p><strong>Advancement.</strong> → Table 3.8: Druid Advancement.</p><h4 id="special-abilities-7" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-7" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Divine Spellcasting.</strong> Druids memorize and cast spells drawn from the Priest spell list, with an emphasis on nature-affecting magic. Full spell progression in Appendix A. Wisdom bonus spells apply as per Table 1.5.</p><p><strong>Identify Plants and Animals.</strong> Druids automatically recognize all natural plants, animals, and pure water within the Known World. This requires no roll.</p><p><strong>Pass Without Trace.</strong> In natural terrain, Druids leave no tracks and make no sound that can be detected by non-magical means. This ability applies to the Druid only.</p><p><strong>Immunity to Woodland Charm.</strong> Druids are immune to charm and hold effects from woodland creatures — fey, dryads, treants, and similar natural beings.</p><p><strong>Shapechange.</strong> At 7th level, Druids can assume the form of any natural animal three times per day. Each change may be to a different form. The Druid retains their own mental ability scores but adopts the physical characteristics of the chosen form. Equipment melds into the new form and reappears on return.</p><p><strong>Hierophantic Rank.</strong> Druid advancement above 11th level is determined through contests with other Druids of equivalent power rather than through experience accumulation. The Known World supports a fixed hierarchy of high-level Druids; advancing beyond the 11th level requires displacing a Druid who holds a position above. The mechanics of this are handled narratively, not through combat alone.</p><p><strong>Druidic Tongue.</strong> Druids learn the Druidic tongue at initiation: a secret language used exclusively for natural and spiritual discourse, taught to no one outside the tradition. See Book II, Chapter 5.</p><p><strong>Skill Points.</strong> Druids start with 5 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 6 and 7.</p><hr><h3 id="table-3-8-druid-advancement" tabindex="-1"><strong>Table 3.8: Druid Advancement</strong> <a class="header-anchor" href="#table-3-8-druid-advancement" aria-label="Permalink to &quot;**Table 3.8: Druid Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d8</td><td>+0</td></tr><tr><td>2</td><td>2,000</td><td>2d8</td><td>+0</td></tr><tr><td>3</td><td>4,000</td><td>3d8</td><td>+1</td></tr><tr><td>4</td><td>7,500</td><td>4d8</td><td>+1</td></tr><tr><td>5</td><td>12,500</td><td>5d8</td><td>+1</td></tr><tr><td>6</td><td>20,000</td><td>6d8</td><td>+2</td></tr><tr><td>7</td><td>35,000</td><td>7d8</td><td>+2</td></tr><tr><td>8</td><td>60,000</td><td>8d8</td><td>+2</td></tr><tr><td>9</td><td>90,000</td><td>9d8</td><td>+3</td></tr><tr><td>10</td><td>125,000</td><td>9d8+2</td><td>+3</td></tr><tr><td>11+</td><td>Contest-based</td><td>+2 HP/level</td><td>+1 per 2 levels</td></tr></tbody></table><hr><h2 id="rogue-group" tabindex="-1"><strong>ROGUE GROUP</strong> <a class="header-anchor" href="#rogue-group" aria-label="Permalink to &quot;**ROGUE GROUP**&quot;">​</a></h2><p>Rogues advance at the same combat rate as Priests but depend on positioning and preparation rather than sustained martial capability. Their value is in what they can do that no one else can: penetrate defenses silently, extract information through social leverage, and make a single well-placed strike count for more than a Warrior&#39;s full engagement.</p><hr><h3 id="thief" tabindex="-1"><strong>THIEF</strong> <a class="header-anchor" href="#thief" aria-label="Permalink to &quot;**THIEF**&quot;">​</a></h3><p>Thieves are specialists in getting access to things that are supposed to be inaccessible. Locks, shadows, pockets, secured rooms, guarded information — these are professional domains, and what distinguishes a Thief from someone who has learned a few tricks is the breadth and depth of that professional skill set.</p><p>In the Known World, Thieves work across a wide operational range: guild operatives in the merchant cities, independent agents selling particular capabilities, spies embedded in political structures, and straightforward criminals whose professional distinction from any other category is primarily a matter of who is paying them and for what. Many end up adventuring because the work is irregular, the income unstable, and the skill set adapts well to contexts where legal distinctions have become largely theoretical.</p><p><strong>Prime Requisite.</strong> Dexterity.</p><p><strong>Requirements.</strong> None.</p><p><strong>Hit Dice.</strong> d6, through level 10. +2 HP/level thereafter.</p><p><strong>Weapons.</strong> Any.</p><p><strong>Armor.</strong> Leather and lighter. Metal armor interferes with thieving skills.</p><p><strong>Advancement.</strong> → Table 3.9: Thief Advancement.</p><h4 id="special-abilities-8" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-8" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Thieving Skills.</strong> Thieves possess a suite of professional skills that improve with level. Each skill begins at a base percentage score determined by the Thief&#39;s Dexterity and ancestry, then advances as the Thief gains levels — the player distributes a pool of percentage points among skills at each level.</p><p>The thieving skills are:</p><ul><li><strong>Pick Pockets</strong> — lift small items from worn locations without detection.</li><li><strong>Open Locks</strong> — defeat mechanical locks with tools. Magical locks require a spell or a separate method.</li><li><strong>Find/Remove Traps</strong> — locate and safely disarm mechanical traps. Requires concentration and time.</li><li><strong>Move Silently</strong> — move without generating detectable sound.</li><li><strong>Hide in Shadows</strong> — become effectively invisible in areas of shadow or darkness.</li><li><strong>Hear Noise</strong> — detect sounds through barriers at distances that defeat normal hearing. Requires quiet and concentration.</li><li><strong>Climb Walls</strong> — ascend and descend surfaces with minimal handholds.</li><li><strong>Read Languages</strong> — decipher written languages not known to the Thief, including codes and ciphers. Requires at least one week of work per attempt.</li></ul><p>Thieving skill scores and advancement tables are in Appendix B.</p><p><strong>Backstab.</strong> When attacking a target from behind who is unaware of the Thief&#39;s presence, the Thief receives +4 to the attack roll and multiplies weapon damage (before Strength modifiers) by their backstab multiplier. The multiplier increases with level: ×2 at levels 1–4, ×3 at levels 5–8, ×4 at levels 9–12, ×5 at levels 13+.</p><p><strong>Thieves&#39; Cant.</strong> Thieves know a professional argot intelligible to other Thieves and certain underworld figures. It conveys professional identity, intent, and basic operational information in terms that sound unremarkable to civilians.</p><p><strong>Skill Points.</strong> Thieves start with 5 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><hr><h3 id="table-3-9-thief-advancement" tabindex="-1"><strong>Table 3.9: Thief Advancement</strong> <a class="header-anchor" href="#table-3-9-thief-advancement" aria-label="Permalink to &quot;**Table 3.9: Thief Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d6</td><td>+0</td></tr><tr><td>2</td><td>1,250</td><td>2d6</td><td>+0</td></tr><tr><td>3</td><td>2,500</td><td>3d6</td><td>+1</td></tr><tr><td>4</td><td>5,000</td><td>4d6</td><td>+1</td></tr><tr><td>5</td><td>10,000</td><td>5d6</td><td>+1</td></tr><tr><td>6</td><td>20,000</td><td>6d6</td><td>+2</td></tr><tr><td>7</td><td>40,000</td><td>7d6</td><td>+2</td></tr><tr><td>8</td><td>70,000</td><td>8d6</td><td>+2</td></tr><tr><td>9</td><td>110,000</td><td>9d6</td><td>+3</td></tr><tr><td>10</td><td>160,000</td><td>10d6</td><td>+3</td></tr><tr><td>11+</td><td>+220,000/level</td><td>+2 HP/level</td><td>+1 per 2 levels</td></tr></tbody></table><hr><h3 id="bard" tabindex="-1"><strong>BARD</strong> <a class="header-anchor" href="#bard" aria-label="Permalink to &quot;**BARD**&quot;">​</a></h3><p>Bards are the Known World&#39;s professional carriers of story. They collect accounts of significant deeds, negotiate their way through social situations that would stop other classes entirely, and move between factions in a way that no other profession manages — because information is a commodity that almost everyone values, and Bards hold more of it than they appear to.</p><p>In the Known World, the shadow of the Vithurian Orchestra falls over every practicing Bard. The Orchestra is not an institution that accepts members, but a standard of excellence at which the best Bards aim and against which all Bards are quietly measured. A Bard who has been immortalized in the Orchestra&#39;s annals is a different kind of person than one who merely calls themselves a Bard. Most Bards who take contracts alongside mercenary companies are doing so because interesting things happen around people who are paid to solve dangerous problems, and interesting things make better material than tavern gossip.</p><p><strong>Prime Requisite.</strong> Charisma.</p><p><strong>Requirements.</strong> DEX 12, INT 13, CHA 13.</p><p><strong>Hit Dice.</strong> d6, through level 10. +2 HP/level thereafter.</p><p><strong>Weapons.</strong> Any. Bards cannot wear metal armor while using their performance abilities.</p><p><strong>Armor.</strong> Leather and lighter for performance. Any armor when not performing.</p><p><strong>Advancement.</strong> → Table 3.10: Bard Advancement.</p><h4 id="special-abilities-9" tabindex="-1"><strong>Special Abilities</strong> <a class="header-anchor" href="#special-abilities-9" aria-label="Permalink to &quot;**Special Abilities**&quot;">​</a></h4><p><strong>Legend Lore.</strong> Bards accumulate historical and regional knowledge as a professional function. The Bard&#39;s player may ask the GM for information about a significant person, place, item, or event. The GM provides accurate information proportional to how well-known the subject is and how long the Bard has had to gather accounts. This is not magical, but the result of actually knowing things.</p><p><strong>Inspire Competence.</strong> Once per combat encounter, a Bard who spends a round performing grants a +1 bonus to attack rolls and saving throws to all allies within 9 m who can hear and understand them. This lasts a number of rounds equal to the Bard&#39;s level.</p><p><strong>Bardic Charm.</strong> Bards receive a bonus to all Charisma-based reaction checks equal to half their level, rounded down. Social encounters with neutral or friendly NPCs start one step more favorably than they otherwise would.</p><p><strong>Spellcasting.</strong> From the 2nd level, Bards access a small pool of Wizard spells. They do not use grimoires — their spells are learned through oral tradition and practical observation, retained in memory rather than written formula. A Bard&#39;s spell selection is limited to spells with verbal or somatic components; those requiring expensive material components are inaccessible unless the Bard can acquire the materials independently. Spell progression is in Appendix A.</p><p>Bards use material components for their wizard spells identically to Generalist Mages — full V + S + M dependency, no school-specific exemptions. Their knowledge is observational rather than architectural; understanding how a spell works in practice is not the same as understanding the sympathetic logic that makes the material anchor redundant. Expensive or specific components listed in spell descriptions remain inaccessible unless acquired independently.</p><p><strong>Thieving Skills.</strong> Bards have access to a reduced set of Thieving skills: Pick Pockets, Hear Noise, Climb Walls, and Read Languages. These function identically to Thief skills but advance more slowly. Bards do not gain Backstab.</p><p><strong>Reputation and the Orchestra.</strong> At the 10th level, the Bard&#39;s name is known beyond their immediate operational area. NPCs with access to bardic networks will have heard of them. At the GM&#39;s discretion, this may include agents of the Vithurian Orchestra, depending on what the Bard has actually done with their career.</p><p><strong>Skill Points.</strong> Bards start with 5 Skill Points (SPs) that can be used to purchase Combat and Non-Combat Skills. See chapters 7 and 8.</p><hr><h3 id="table-3-10-bard-advancement" tabindex="-1"><strong>Table 3.10: Bard Advancement</strong> <a class="header-anchor" href="#table-3-10-bard-advancement" aria-label="Permalink to &quot;**Table 3.10: Bard Advancement**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>XP</th><th>Hit Dice</th><th>Attack Bonus</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>1d6</td><td>+0</td></tr><tr><td>2</td><td>1,500</td><td>2d6</td><td>+0</td></tr><tr><td>3</td><td>3,000</td><td>3d6</td><td>+1</td></tr><tr><td>4</td><td>6,000</td><td>4d6</td><td></td></tr></tbody></table>',283)])])}const m=e(i,[["render",o]]);export{g as __pageData,m as default};
